import { ref, Ref } from 'vue'
import { getAlertMetricMeta } from '../utils/alertMetrics'

function isProxmoxMetric(metric: string): boolean {
  return getAlertMetricMeta(metric).category === 'proxmox'
}

function isProxmoxGuestMetric(metric: string): boolean {
  return metric === 'proxmox_guest_cpu_percent' || metric === 'proxmox_guest_memory_percent'
}

function isProxmoxDiskMetric(metric: string): boolean {
  return metric === 'proxmox_disk_failed_count' || metric === 'proxmox_disk_min_wearout_percent'
}

function isProxmoxCountMetric(metric: string): boolean {
  const meta = getAlertMetricMeta(metric)
  return meta.category === 'proxmox' && meta.unit === ''
}

interface CommandTrigger {
  module: string
  action: string
  target: string
}

interface AlertRuleFormActions {
  channels: string[]
  smtp_to: string
  ntfy_topic: string
  cooldown: number
  command_trigger?: CommandTrigger
}

interface ProxmoxScope {
  scope_mode: string
  connection_id: string
  node_id: string
  storage_id: string
  guest_id: string
  disk_id: string
}

interface AlertRuleFormData {
  name: string
  enabled: boolean
  source_type: 'agent' | 'proxmox'
  host_id: string | null
  proxmox_scope: ProxmoxScope
  metric: string
  operator: string
  threshold: number
  duration: number
  actions: AlertRuleFormActions
}

interface AlertRuleFormApi {
  form: Ref<AlertRuleFormData>
  channelSmtp: Ref<boolean>
  channelNtfy: Ref<boolean>
  channelBrowser: Ref<boolean>
  commandTriggerEnabled: Ref<boolean>
  defaultCommandTrigger: () => CommandTrigger
  defaultForm: () => AlertRuleFormData
  hydrateFormFromRule: (rule: any) => void
  onMetricChange: () => void
  buildPayload: () => any
}

export function useAlertRuleForm(): AlertRuleFormApi {
  const channelSmtp: Ref<boolean> = ref(false)
  const channelNtfy: Ref<boolean> = ref(false)
  const channelBrowser: Ref<boolean> = ref(false)
  const commandTriggerEnabled: Ref<boolean> = ref(false)

  const defaultCommandTrigger = (): CommandTrigger => ({ module: 'processes', action: 'list', target: '' })
  const defaultForm = (): AlertRuleFormData => ({
    name: '',
    enabled: true,
    source_type: 'agent',
    host_id: null,
    metric: 'cpu',
    proxmox_scope: {
      scope_mode: 'global',
      connection_id: '',
      node_id: '',
      storage_id: '',
      guest_id: '',
      disk_id: '',
    },
    operator: '>',
    threshold: 80,
    duration: 300,
    actions: {
      channels: [],
      smtp_to: '',
      ntfy_topic: '',
      cooldown: 3600,
      command_trigger: defaultCommandTrigger(),
    },
  })

  const form: Ref<AlertRuleFormData> = ref(defaultForm())

  function hydrateFormFromRule(rule: any): void {
    if (!rule) {
      form.value = defaultForm()
      channelSmtp.value = false
      channelNtfy.value = false
      channelBrowser.value = false
      commandTriggerEnabled.value = false
      return
    }

    const actions = rule.actions || {}
    const scope = rule.proxmox_scope || {}
    const commandTrigger = actions.command_trigger

    form.value = {
      name: rule.name || '',
      enabled: rule.enabled,
        source_type: rule.source_type || (isProxmoxMetric(rule.metric) ? 'proxmox' : 'agent'),
      host_id: rule.host_id,
      metric: rule.metric,
        proxmox_scope: {
          scope_mode: scope.scope_mode || 'global',
          connection_id: scope.connection_id || '',
          node_id: scope.node_id || '',
          storage_id: scope.storage_id || '',
          guest_id: scope.guest_id || '',
          disk_id: scope.disk_id || '',
        },
      operator: rule.operator,
      threshold: rule.threshold,
      duration: rule.duration_seconds,
      actions: {
        channels: actions.channels || [],
        smtp_to: actions.smtp_to || '',
        ntfy_topic: actions.ntfy_topic || '',
        cooldown: actions.cooldown || 3600,
        command_trigger: commandTrigger
          ? { module: commandTrigger.module, action: commandTrigger.action, target: commandTrigger.target || '' }
          : defaultCommandTrigger(),
      },
    }

    channelSmtp.value = actions.channels?.includes('smtp') || false
    channelNtfy.value = actions.channels?.includes('ntfy') || false
    channelBrowser.value = actions.channels?.includes('browser') || false
    commandTriggerEnabled.value = !!commandTrigger
  }

  function onMetricChange(): void {
    if (form.value.metric === 'heartbeat_timeout') {
      form.value.source_type = 'agent'
      form.value.operator = '>'
      if (!form.value.threshold || form.value.threshold === 80) {
        form.value.threshold = 300
      }
      form.value.duration = 0
      return
    }

    if (isProxmoxMetric(form.value.metric)) {
      form.value.source_type = 'proxmox'
      form.value.host_id = null

      if (isProxmoxGuestMetric(form.value.metric)) {
        form.value.proxmox_scope.scope_mode = 'guest'
      } else if (isProxmoxDiskMetric(form.value.metric)) {
        form.value.proxmox_scope.scope_mode = 'disk'
      } else if (form.value.proxmox_scope.scope_mode === 'guest' || form.value.proxmox_scope.scope_mode === 'disk') {
        form.value.proxmox_scope.scope_mode = 'global'
        form.value.proxmox_scope.guest_id = ''
        form.value.proxmox_scope.disk_id = ''
      }
    } else {
      form.value.source_type = 'agent'
    }

    if (form.value.metric === 'proxmox_disk_min_wearout_percent') {
      form.value.operator = '<'
      if (!form.value.threshold || form.value.threshold === 80) {
        form.value.threshold = 20
      }
      return
    }

    if (isProxmoxCountMetric(form.value.metric)) {
      form.value.operator = '>'
      if (!form.value.threshold || form.value.threshold === 80) {
        form.value.threshold = 0.5
      }
      form.value.duration = 0
      return
    }

    if (form.value.metric === 'status_offline' || form.value.metric === 'disk_smart_status') {
      form.value.operator = '>'
      form.value.threshold = 0.5
      form.value.duration = 0
    }
  }

  function buildPayload(): any {
    const channels: string[] = []
    if (channelSmtp.value) channels.push('smtp')
    if (channelNtfy.value) channels.push('ntfy')
    if (channelBrowser.value) channels.push('browser')

    const actions: any = {
      ...form.value.actions,
      channels,
    }

    if (!commandTriggerEnabled.value) {
      delete actions.command_trigger
    }

    return {
      ...form.value,
      source_type: form.value.source_type,
      proxmox_scope: isProxmoxMetric(form.value.metric) ? { ...form.value.proxmox_scope } : null,
      actions,
    }
  }

  return {
    form,
    channelSmtp,
    channelNtfy,
    channelBrowser,
    commandTriggerEnabled,
    defaultCommandTrigger,
    defaultForm,
    hydrateFormFromRule,
    onMetricChange,
    buildPayload,
  }
}

import { computed, ComputedRef, Ref, ref } from 'vue'
import { useConfirmDialog } from './useConfirmDialog'
import { useDateFormatter } from './useDateFormatter'
import { useHostsStore } from '../stores/hosts'
import { useAlertRulesStore } from '../stores/alertRules'
import apiClient from '../api'
import { storeToRefs } from 'pinia'

interface Host {
  id: string
  [key: string]: any
}

interface AlertRule {
  id: number
  name: string
  enabled: boolean
  [key: string]: any
}

interface Incident {
  id: string
  resolved_at?: string | null
  [key: string]: any
}

interface Notification {
  type: string
  notification?: any
}

interface AlertRuleCapabilities {
  metrics: any[]
  agent_metrics?: any[]
  proxmox_metrics?: any[]
  proxmox_scope: {
    modes: string[]
    connections: any[]
    nodes: any[]
    storages: any[]
    guests: any[]
    disks: any[]
  }
}

interface UseAlertsPageApi {
  alertsTab: Ref<string>
  incidents: Ref<Incident[]>
  incidentsLoading: Ref<boolean>
  incidentsError: Ref<string>
  incidentsLoaded: Ref<boolean>
  rules: Ref<AlertRule[]>
  hosts: Ref<Host[]>
  loading: Ref<boolean>
  fetched: Ref<boolean>
  fetchError: Ref<string>
  showModal: Ref<boolean>
  saving: Ref<boolean>
  saveError: Ref<string>
  editingRule: Ref<AlertRule | null>
  capabilities: Ref<AlertRuleCapabilities | null>
  capabilitiesLoading: Ref<boolean>
  capabilitiesError: Ref<string>
  activeIncidentCount: ComputedRef<number>
  init: () => Promise<void>
  loadIncidents: () => Promise<void>
  switchToIncidents: () => Promise<void>
  startAddAlert: () => void
  startEditAlert: (rule: AlertRule) => void
  saveAlert: (payload: any) => Promise<void>
  toggleEnabled: (rule: AlertRule) => Promise<void>
  deleteAlert: (rule: AlertRule) => Promise<void>
  closeModal: () => void
  formatDate: (dateStr: string) => string
  onWebSocketAlert: (payload: Notification) => void
}

export function useAlertsPage(): UseAlertsPageApi {
  const { confirm } = useConfirmDialog()
  const { formatLocaleDateTime } = useDateFormatter()
  const hostsStore = useHostsStore()
  const rulesStore = useAlertRulesStore()

  const alertsTab: Ref<string> = ref('rules')
  const incidents: Ref<Incident[]> = ref([])
  const incidentsLoading: Ref<boolean> = ref(false)
  const incidentsError: Ref<string> = ref('')
  const incidentsLoaded: Ref<boolean> = ref(false)
  const showModal: Ref<boolean> = ref(false)
  const saving: Ref<boolean> = ref(false)
  const saveError: Ref<string> = ref('')
  const editingRule: Ref<AlertRule | null> = ref(null)
  const capabilities: Ref<AlertRuleCapabilities | null> = ref(null)
  const capabilitiesLoading: Ref<boolean> = ref(false)
  const capabilitiesError: Ref<string> = ref('')

  // Expose store state (reactive refs shared across navigations)
  const { rules, loading, fetched, error: fetchError } = storeToRefs(rulesStore)
  const { hosts } = storeToRefs(hostsStore)

  const activeIncidentCount: ComputedRef<number> = computed(
    () => incidents.value.filter((incident) => !incident.resolved_at).length
  )

  async function init(): Promise<void> {
    capabilitiesLoading.value = true
    capabilitiesError.value = ''

    const [rulesResult, hostsResult, agentCapsResult, proxmoxCapsResult] = await Promise.allSettled([
      rulesStore.fetchRules(),
      hostsStore.fetchHosts(),
      apiClient.getAgentAlertRuleCapabilities(),
      apiClient.getProxmoxAlertRuleCapabilities(),
    ])

    if (agentCapsResult.status === 'fulfilled' && proxmoxCapsResult.status === 'fulfilled') {
      const agentMetrics = agentCapsResult.value?.data?.metrics || []
      const proxmoxMetrics = proxmoxCapsResult.value?.data?.proxmox_metrics || []
      const proxmoxScope = proxmoxCapsResult.value?.data?.proxmox_scope || {
        modes: [],
        connections: [],
        nodes: [],
        storages: [],
        guests: [],
        disks: [],
      }
      capabilities.value = {
        metrics: [...agentMetrics, ...proxmoxMetrics],
        agent_metrics: agentMetrics,
        proxmox_metrics: proxmoxMetrics,
        proxmox_scope: proxmoxScope,
      }
    } else {
      capabilitiesError.value = 'Impossible de charger les capacites des metriques'
    }

    capabilitiesLoading.value = false

    if (!rulesStore.fetched && !rulesStore.loading) {
      await rulesStore.fetchRules(true)
    }

    if (rulesResult.status === 'rejected' || hostsResult.status === 'rejected') {
      // Keep existing store-managed error handling behavior.
    }
  }

  async function loadIncidents(): Promise<void> {
    incidentsLoading.value = true
    incidentsError.value = ''
    try {
      const response = await apiClient.getNotifications()
      incidents.value = response.data?.notifications || []
      incidentsLoaded.value = true
    } catch {
      incidentsError.value = 'Impossible de charger les incidents'
    } finally {
      incidentsLoading.value = false
    }
  }

  async function switchToIncidents(): Promise<void> {
    alertsTab.value = 'incidents'
    if (!incidentsLoaded.value) await loadIncidents()
  }

  function startAddAlert(): void {
    editingRule.value = null
    saveError.value = ''
    showModal.value = true
  }

  function startEditAlert(rule: AlertRule): void {
    editingRule.value = rule
    saveError.value = ''
    showModal.value = true
  }

  async function saveAlert(payload: any): Promise<void> {
    saveError.value = ''
    saving.value = true
    try {
      if (editingRule.value) {
        await apiClient.updateAlertRule(editingRule.value.id, payload)
      } else {
        await apiClient.createAlertRule(payload)
      }
      await rulesStore.fetchRules(true)
      closeModal()
    } catch (err: any) {
      saveError.value = 'Erreur : ' + (err.response?.data?.error || err.message)
    } finally {
      saving.value = false
    }
  }

  async function toggleEnabled(rule: AlertRule): Promise<void> {
    try {
      const nextEnabled = !rule.enabled
      await apiClient.updateAlertRule(rule.id, { enabled: nextEnabled })
      await rulesStore.fetchRules(true)
      if (!nextEnabled && incidentsLoaded.value) {
        await loadIncidents()
      }
    } catch {
      // ignore
    }
  }

  async function deleteAlert(rule: AlertRule): Promise<void> {
    const confirmed = await confirm({
      title: "Supprimer l'alerte ?",
      message: `Voulez-vous vraiment supprimer la regle "${rule.name || 'Sans nom'}" ?\n\nCette action est irreversible.`,
      variant: 'danger',
    })
    if (!confirmed) return

    try {
      await apiClient.deleteAlertRule(rule.id)
      await rulesStore.fetchRules(true)
    } catch (err: any) {
      saveError.value = 'Erreur lors de la suppression : ' + (err.response?.data?.error || err.message)
    }
  }

  function closeModal(): void {
    showModal.value = false
    editingRule.value = null
    saveError.value = ''
  }

  function formatDate(dateStr: string): string {
    return formatLocaleDateTime(dateStr)
  }

  function onWebSocketAlert(payload: Notification): void {
    // Incident created or resolved — refresh the list
    if (payload.type === 'alert_incident_update') {
      loadIncidents()
      return
    }

    if (payload.type !== 'new_alert' || !payload.notification) return

    const incoming = payload.notification
    const idx = incidents.value.findIndex((item) => item.id === incoming.id)

    if (idx >= 0) {
      incidents.value = [
        { ...incidents.value[idx], ...incoming },
        ...incidents.value.slice(0, idx),
        ...incidents.value.slice(idx + 1),
      ]
    } else {
      incidents.value = [incoming, ...incidents.value]
    }

    incidentsLoaded.value = true
    loadIncidents()
  }

  return {
    alertsTab,
    incidents,
    incidentsLoading,
    incidentsError,
    incidentsLoaded,
    rules: rules as any,
    hosts: hosts as any,
    loading: loading as any,
    fetched: fetched as any,
    fetchError: fetchError as any,
    showModal,
    saving,
    saveError,
    editingRule,
    capabilities,
    capabilitiesLoading,
    capabilitiesError,
    activeIncidentCount,
    init,
    loadIncidents,
    switchToIncidents,
    startAddAlert,
    startEditAlert,
    saveAlert,
    toggleEnabled,
    deleteAlert,
    closeModal,
    formatDate,
    onWebSocketAlert,
  }
}

import { getCurrentInstance, onUnmounted } from 'vue'

type TokenSource = string | { value: string } | (() => string)

interface CommandStreamOptions {
  onInit?: (payload: any) => void
  onChunk?: (payload: any) => void
  onStatus?: (payload: any) => void
  onClose?: () => void
  onError?: (error: Error) => void
  closeOnTerminalStatus?: boolean
  terminalCloseDelayMs?: number
}

interface CollectCommandOutputOptions {
  timeoutMs?: number
  onInit?: (payload: any, output: string) => void
  onChunk?: (payload: any, output: string) => void
  onStatus?: (payload: any, output: string) => void
}

interface UseCommandStreamApi {
  openCommandStream: (commandId: string, options?: CommandStreamOptions) => WebSocket
  collectCommandOutput: (commandId: string, options?: CollectCommandOutputOptions) => Promise<string>
  closeStream: () => void
}

function resolveToken(tokenSource: TokenSource): string {
  if (typeof tokenSource === 'function') return tokenSource() || ''
  if (tokenSource && typeof tokenSource === 'object' && 'value' in tokenSource)
    return (tokenSource as { value: string }).value || ''
  return tokenSource || ''
}

function isTerminalStatus(status: string): boolean {
  return status === 'completed' || status === 'failed'
}

export function useCommandStream({ token }: { token: TokenSource }): UseCommandStreamApi {
  let activeStream: WebSocket | null = null

  function closeStream(): void {
    if (!activeStream) return
    activeStream.onopen = null
    activeStream.onmessage = null
    activeStream.onerror = null
    activeStream.onclose = null
    activeStream.close()
    activeStream = null
  }

  function createStreamUrl(commandId: string): string {
    const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws'
    return `${protocol}://${window.location.host}/api/v1/ws/commands/stream/${commandId}`
  }

  function openCommandStream(commandId: string, options: CommandStreamOptions = {}): WebSocket {
    const {
      onInit,
      onChunk,
      onStatus,
      onClose,
      onError,
      closeOnTerminalStatus = false,
      terminalCloseDelayMs = 500,
    } = options

    closeStream()

    const ws = new WebSocket(createStreamUrl(commandId))
    activeStream = ws

    const closeIfCurrent = (): void => {
      if (activeStream !== ws) return
      closeStream()
    }

    const scheduleTerminalClose = (status: string): void => {
      if (!closeOnTerminalStatus || !isTerminalStatus(status)) return
      window.setTimeout(closeIfCurrent, terminalCloseDelayMs)
    }

    ws.onopen = (): void => {
      if (activeStream !== ws) return
      ws.send(JSON.stringify({ type: 'auth', token: resolveToken(token) }))
    }

    ws.onmessage = (event: MessageEvent): void => {
      if (activeStream !== ws) return
      try {
        const payload = JSON.parse(event.data)
        if (payload.type === 'cmd_stream_init') {
          onInit?.(payload)
          scheduleTerminalClose(payload.status)
        } else if (payload.type === 'cmd_stream') {
          onChunk?.(payload)
        } else if (payload.type === 'cmd_status_update') {
          onStatus?.(payload)
          scheduleTerminalClose(payload.status)
        }
      } catch {
        // Ignore malformed payloads
      }
    }

    ws.onerror = (): void => {
      if (activeStream !== ws) return
      // Close before calling the error callback so the dead socket doesn't
      // linger. closeStream() nullifies all handlers first, so onclose won't
      // fire a second time after this.
      closeStream()
      onError?.(new Error('WebSocket error'))
    }

    ws.onclose = (): void => {
      const wasCurrent = activeStream === ws
      if (wasCurrent) activeStream = null
      onClose?.()
    }

    return ws
  }

  function collectCommandOutput(
    commandId: string,
    options: CollectCommandOutputOptions = {}
  ): Promise<string> {
    const { timeoutMs = 20000, onInit, onChunk, onStatus } = options

    return new Promise((resolve, reject) => {
      let output = ''
      let settled = false
      let timeoutId: number | null = null

      const finishResolve = (value: string): void => {
        if (settled) return
        settled = true
        if (timeoutId) window.clearTimeout(timeoutId)
        closeStream()
        resolve(value)
      }

      const finishReject = (reason: Error): void => {
        if (settled) return
        settled = true
        if (timeoutId) window.clearTimeout(timeoutId)
        closeStream()
        reject(reason)
      }

      openCommandStream(commandId, {
        onInit: (payload: any) => {
          output = payload.output || ''
          onInit?.(payload, output)
          if (payload.status === 'completed') finishResolve(output)
          else if (payload.status === 'failed') finishReject(new Error(output || 'Command failed'))
        },
        onChunk: (payload: any) => {
          output += payload.chunk || ''
          onChunk?.(payload, output)
        },
        onStatus: (payload: any) => {
          if (typeof payload.output === 'string') output = payload.output
          onStatus?.(payload, output)
          if (payload.status === 'completed') finishResolve(output)
          else if (payload.status === 'failed') finishReject(new Error(output || 'Command failed'))
        },
        onClose: () => {
          if (!settled)
            finishReject(new Error('Connexion WebSocket fermée avant la fin de la commande'))
        },
        onError: (error: Error) => {
          finishReject(error)
        },
      })

      timeoutId = window.setTimeout(() => {
        finishReject(new Error('Timeout'))
      }, timeoutMs)
    })
  }

  if (getCurrentInstance()) {
    onUnmounted(() => {
      closeStream()
    })
  }

  return {
    openCommandStream,
    collectCommandOutput,
    closeStream,
  }
}

import { ref, computed, watch, onMounted } from 'vue'
import { storeToRefs } from 'pinia'
import apiClient from '../api'
import { useAuthStore } from '../stores/auth'
import { useDashboardStore } from '../stores/dashboard'
import { useWebSocket } from './useWebSocket'
import { useConfirmDialog } from './useConfirmDialog'
import { translateError } from '../utils/translateError'
import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'
import utc from 'dayjs/plugin/utc'
import 'dayjs/locale/fr'

dayjs.extend(relativeTime)
dayjs.extend(utc)
dayjs.locale('fr')

type AnyRecord = Record<string, any>
type SortDirection = 'asc' | 'desc'
type HostStatus = 'online' | 'warning' | 'offline'

interface SummaryDataset {
  label: string
  data: number[]
  borderColor: string
  backgroundColor: string
  fill: boolean
}

interface SummaryChartData {
  labels: string[]
  datasets: SummaryDataset[]
}

interface DashboardChartPalette {
  legendText: string
  tickText: string
  grid: string
  tooltipBackground: string
  tooltipText: string
  tooltipBorder: string
  cpuBorder: string
  cpuBackground: string
  ramBorder: string
  ramBackground: string
}

const FALLBACK_CHART_PALETTE: DashboardChartPalette = {
  legendText: '#1f2937',
  tickText: '#1f2937',
  grid: 'rgba(107,114,128,0.15)',
  tooltipBackground: 'rgba(17,24,39,0.90)',
  tooltipText: '#ffffff',
  tooltipBorder: '#4b5563',
  cpuBorder: '#206bc4',
  cpuBackground: 'rgba(32,107,196,0.12)',
  ramBorder: '#2fb344',
  ramBackground: 'rgba(47,179,68,0.12)',
}

function getThemeStyles(): { body: CSSStyleDeclaration | null; root: CSSStyleDeclaration | null } | null {
  if (typeof window === 'undefined' || typeof document === 'undefined') return null
  return {
    body: document.body ? window.getComputedStyle(document.body) : null,
    root: window.getComputedStyle(document.documentElement),
  }
}

function getCssVarValue(name: string, fallback: string): string {
  const styles = getThemeStyles()
  if (!styles) return fallback
  const value = styles.body?.getPropertyValue(name).trim() || styles.root?.getPropertyValue(name).trim() || ''
  return value || fallback
}

function isDarkRgbColor(color: string): boolean {
  const rgb = color.match(/^rgb\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*\)$/i)
  const rgba = color.match(/^rgba\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*,\s*([0-9]*\.?[0-9]+)\s*\)$/i)
  const values = rgb || rgba
  if (!values) return false

  const r = Number(values[1])
  const g = Number(values[2])
  const b = Number(values[3])
  const luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255
  return luminance < 0.5
}

function resolveCssColorForCanvas(color: string, fallback: string): string {
  if (!color) return fallback
  if (typeof window === 'undefined' || typeof document === 'undefined') return fallback

  const probe = document.createElement('span')
  probe.style.color = color
  probe.style.position = 'fixed'
  probe.style.left = '-9999px'
  probe.style.top = '-9999px'
  probe.style.visibility = 'hidden'

  document.body.appendChild(probe)
  const resolved = window.getComputedStyle(probe).color.trim()
  document.body.removeChild(probe)

  if (!resolved || resolved === 'rgba(0, 0, 0, 0)' || resolved === 'transparent') {
    return fallback
  }
  return resolved
}

function toRgba(color: string, alpha: number, fallback: string): string {
  const clamped = Math.max(0, Math.min(1, alpha))
  const hex = color.match(/^#([0-9a-f]{3}|[0-9a-f]{6})$/i)
  if (hex) {
    const raw = hex[1]
    const normalized = raw.length === 3 ? raw.split('').map((c) => c + c).join('') : raw
    const int = Number.parseInt(normalized, 16)
    const r = (int >> 16) & 255
    const g = (int >> 8) & 255
    const b = int & 255
    return `rgba(${r},${g},${b},${clamped})`
  }

  const rgb = color.match(/^rgb\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*\)$/i)
  if (rgb) {
    return `rgba(${rgb[1]},${rgb[2]},${rgb[3]},${clamped})`
  }

  const rgba = color.match(/^rgba\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*,\s*([0-9]*\.?[0-9]+)\s*\)$/i)
  if (rgba) {
    return `rgba(${rgba[1]},${rgba[2]},${rgba[3]},${clamped})`
  }

  return fallback
}

function getDashboardChartPalette(): DashboardChartPalette {
  const pageBackground = resolveCssColorForCanvas(
    getCssVarValue('--tblr-bg-surface', getCssVarValue('--tblr-body-bg', '#111827')),
    '#111827',
  )
  const lightText = resolveCssColorForCanvas(getCssVarValue('--tblr-light', '#f8fafc'), '#f8fafc')
  const darkText = resolveCssColorForCanvas(getCssVarValue('--tblr-dark', '#111827'), '#111827')
  const textOnPage = isDarkRgbColor(pageBackground) ? lightText : darkText
  const legendText = textOnPage
  const tickText = toRgba(textOnPage, 0.82, textOnPage)
  const gridBase = resolveCssColorForCanvas(
    getCssVarValue('--tblr-border-color', FALLBACK_CHART_PALETTE.tooltipBorder),
    FALLBACK_CHART_PALETTE.tooltipBorder,
  )
  const tooltipText = textOnPage
  const primary = resolveCssColorForCanvas(
    getCssVarValue('--tblr-primary', FALLBACK_CHART_PALETTE.cpuBorder),
    FALLBACK_CHART_PALETTE.cpuBorder,
  )
  const success = resolveCssColorForCanvas(
    getCssVarValue('--tblr-success', FALLBACK_CHART_PALETTE.ramBorder),
    FALLBACK_CHART_PALETTE.ramBorder,
  )

  return {
    legendText,
    tickText,
    grid: toRgba(gridBase, 0.35, FALLBACK_CHART_PALETTE.grid),
    tooltipBackground: pageBackground,
    tooltipText,
    tooltipBorder: resolveCssColorForCanvas(gridBase, FALLBACK_CHART_PALETTE.tooltipBorder),
    cpuBorder: primary,
    cpuBackground: toRgba(primary, 0.12, FALLBACK_CHART_PALETTE.cpuBackground),
    ramBorder: success,
    ramBackground: toRgba(success, 0.12, FALLBACK_CHART_PALETTE.ramBackground),
  }
}

export function useDashboard() {
  const dashboardStore = useDashboardStore()
  const {
    hosts,
    aptPending,
    versionComparisons,
    proxmoxSummary,
    hasProxmox,
    outdatedDockerImages,
  } = storeToRefs(dashboardStore)

  const latestAgentVersion = ref('')
  const cveSummary = ref<AnyRecord | null>(null)
  const proxmoxNodes = ref<AnyRecord[]>([])
  const proxmoxLinks = ref<AnyRecord[]>([])

  const hostMetrics = ref<Record<string, AnyRecord>>({})
  const aptPendingHosts = ref<Record<string, number>>({})
  const diskUsage = ref<Record<string, number>>({})
  const loading = ref(true)

  const searchQuery = ref('')
  const statusFilter = ref('all')
  const sortKey = ref(localStorage.getItem('dashboard.sortKey') || 'name')
  const sortDir = ref<SortDirection>((localStorage.getItem('dashboard.sortDir') as SortDirection) || 'asc')
  watch(sortKey, (v) => localStorage.setItem('dashboard.sortKey', v))
  watch(sortDir, (v) => localStorage.setItem('dashboard.sortDir', v))

  const selectedHostIds = ref<string[]>([])
  const aptLoading = ref('')
  const showDockerVersions = ref(false)

  const summaryHours = ref(24)
  const summaryChartData = ref<SummaryChartData | null>(null)
  const summaryLoading = ref(false)
  const chartSource = ref('agents')
  const chartSources = [
    { key: 'agents', label: 'Agents hôtes' },
    { key: 'proxmox', label: 'Nœuds Proxmox' },
  ]

  const auth = useAuthStore()
  const dialog = useConfirmDialog()

  const selectedCount = computed(() => selectedHostIds.value.length)
  const canRunApt = computed(() => auth.role === 'admin' || auth.role === 'operator')

  const proxmoxLinkByHostId = computed(() => {
    const m: Record<string, AnyRecord> = {}
    for (const link of proxmoxLinks.value) {
      m[link.host_id] = link
    }
    return m
  })

  function effectiveMetrics(hostId: string) {
    const link = proxmoxLinkByHostId.value[hostId]
    const agent = hostMetrics.value[hostId]

    if (link) {
      const src = link.metrics_source
      const useProxmox = src === 'proxmox' || (src === 'auto' && link.cpu_usage != null)
      if (useProxmox) {
        const cpu = link.cpu_usage != null ? link.cpu_usage * 100 : null
        const memPct = link.mem_alloc > 0 ? (link.mem_usage / link.mem_alloc) * 100 : null
        return { cpu, memPct, source: 'proxmox' }
      }
    }
    return {
      cpu: agent?.cpu_usage_percent ?? null,
      memPct: agent?.memory_percent ?? null,
      source: 'agent',
    }
  }

  const filteredHosts = computed(() => {
    const query = searchQuery.value.trim().toLowerCase()
    return hosts.value.filter((host: AnyRecord) => {
      if (statusFilter.value !== 'all' && host.status !== statusFilter.value) return false
      if (!query) return true
      return [host.name, host.hostname, host.ip_address, host.os]
        .filter(Boolean)
        .join(' ')
        .toLowerCase()
        .includes(query)
    })
  })

  const sortedHosts = computed(() => {
    const list = [...filteredHosts.value]
    const direction = sortDir.value === 'asc' ? 1 : -1
    const statusOrder: Record<HostStatus, number> = { online: 0, warning: 1, offline: 2 }

    list.sort((a: AnyRecord, b: AnyRecord) => {
      let aVal, bVal
      switch (sortKey.value) {
        case 'status':
          aVal = statusOrder[(a.status as HostStatus)] ?? 99
          bVal = statusOrder[(b.status as HostStatus)] ?? 99
          break
        case 'cpu':
          aVal = effectiveMetrics(a.id).cpu ?? -1
          bVal = effectiveMetrics(b.id).cpu ?? -1
          break
        case 'apt':
          aVal = aptPendingHosts.value[a.id] ?? 0
          bVal = aptPendingHosts.value[b.id] ?? 0
          break
        case 'last_seen':
          aVal = a.last_seen ? new Date(a.last_seen).getTime() : 0
          bVal = b.last_seen ? new Date(b.last_seen).getTime() : 0
          break
        default:
          aVal = (a.name || a.hostname || '').toLowerCase()
          bVal = (b.name || b.hostname || '').toLowerCase()
      }
      if (aVal < bVal) return -1 * direction
      if (aVal > bVal) return 1 * direction
      return 0
    })
    return list
  })

  const summaryChartOptions = computed(() => {
    const colors = getDashboardChartPalette()
    return {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: true, position: 'top', labels: { color: colors.legendText, boxWidth: 12, padding: 12 } },
        tooltip: {
          enabled: true,
          mode: 'index',
          intersect: false,
          backgroundColor: colors.tooltipBackground,
          titleColor: colors.tooltipText,
          bodyColor: colors.tooltipText,
          borderColor: colors.tooltipBorder,
          borderWidth: 1,
          padding: 10,
          callbacks: {
            label: (ctx: AnyRecord) => `${ctx.dataset.label}: ${ctx.parsed.y.toFixed(1)}%`,
          },
        },
      },
      scales: {
        x: { display: true, grid: { color: colors.grid }, ticks: { color: colors.tickText, maxTicksLimit: 10 } },
        y: { display: true, min: 0, max: 100, grid: { color: colors.grid }, ticks: { color: colors.tickText } },
      },
      elements: { point: { radius: 0, hitRadius: 10, hoverRadius: 5 }, line: { tension: 0.3 } },
      interaction: { mode: 'nearest', axis: 'x', intersect: false },
    }
  })

  const proxmoxAutoSwitched = ref(false)

  const { wsStatus, wsError, retryCount, reconnect } = useWebSocket('/api/v1/ws/dashboard', (payload: AnyRecord) => {
    if (payload.type !== 'dashboard') return
    dashboardStore.setHosts(payload.hosts || [])
    hostMetrics.value = payload.host_metrics || {}
    dashboardStore.setVersionComparisons(payload.version_comparisons || [])
    dashboardStore.setAptPending(payload.apt_pending ?? 0)
    aptPendingHosts.value = payload.apt_pending_hosts || {}
    diskUsage.value = payload.disk_usage || {}
    proxmoxNodes.value = payload.proxmox_nodes || []
    proxmoxLinks.value = payload.proxmox_links || []
    selectedHostIds.value = selectedHostIds.value.filter((id) => hosts.value.some((h: AnyRecord) => h.id === id))
    loading.value = false

    if (!proxmoxAutoSwitched.value && proxmoxNodes.value.length > 0) {
      proxmoxAutoSwitched.value = true
      chartSource.value = 'proxmox'
      fetchSummary()
    }
  }, { debounceMs: 200 })

  function bucketMinutesFor(hours: number) {
    if (hours <= 6) return 1
    if (hours <= 24) return 5
    if (hours <= 168) return 15
    return 60
  }

  async function fetchSummary() {
    summaryLoading.value = true
    try {
      const colors = getDashboardChartPalette()
      const bucketMinutes = bucketMinutesFor(summaryHours.value)
      const isProxmox = chartSource.value === 'proxmox'
      const res = isProxmox
        ? await apiClient.getProxmoxNodeMetrics(summaryHours.value, bucketMinutes)
        : await apiClient.getMetricsSummary(summaryHours.value, bucketMinutes)

      const points: AnyRecord[] = Array.isArray(res.data) ? res.data : []
      if (!points.length) {
        summaryChartData.value = null
        return
      }

      const labels = points.map((p: AnyRecord) =>
        summaryHours.value >= 24 ? dayjs(p.timestamp).format('DD/MM HH:mm') : dayjs(p.timestamp).format('HH:mm')
      )
      summaryChartData.value = {
        labels,
        datasets: [
          {
            label: 'CPU %',
            data: points.map((p: AnyRecord) => Number(p.cpu_avg ?? 0)),
            borderColor: colors.cpuBorder,
            backgroundColor: colors.cpuBackground,
            fill: true,
          },
          {
            label: 'RAM %',
            data: points.map((p: AnyRecord) => Number(p.memory_avg ?? 0)),
            borderColor: colors.ramBorder,
            backgroundColor: colors.ramBackground,
            fill: true,
          },
        ],
      }
    } catch {
      summaryChartData.value = null
    } finally {
      summaryLoading.value = false
    }
  }

  function changeSummaryRange(hours: number) {
    summaryHours.value = hours
    fetchSummary()
  }

  function selectAllFiltered() {
    const ids = sortedHosts.value.map((h: AnyRecord) => h.id)
    selectedHostIds.value = Array.from(new Set([...selectedHostIds.value, ...ids]))
  }

  function clearSelection() {
    selectedHostIds.value = []
  }

  async function sendBulkApt(command: string) {
    if (!selectedHostIds.value.length || aptLoading.value) return
    const hostnames = hosts.value
      .filter((h: AnyRecord) => selectedHostIds.value.includes(h.id))
      .map((h: AnyRecord) => h.hostname || h.name)
      .join(', ')
    const confirmed = await dialog.confirm({
      title: `apt ${command}`,
      message: `Exécuter sur ${selectedHostIds.value.length} hôte(s) :\n${hostnames}`,
      variant: 'warning',
    })
    if (!confirmed) return
    aptLoading.value = command
    try {
      await apiClient.sendAptCommand(selectedHostIds.value, command)
    } catch (e: any) {
      await dialog.confirm({ title: 'Erreur', message: translateError(e), variant: 'danger' })
    } finally {
      aptLoading.value = ''
    }
  }

  function formatUptime(seconds: number) {
    if (!seconds) return 'N/A'
    const days = Math.floor(seconds / 86400)
    const hours = Math.floor((seconds % 86400) / 3600)
    if (days > 0) return `${days}j ${hours}h`
    return `${hours}h ${Math.floor((seconds % 3600) / 60)}m`
  }

  function cpuColor(pct: number | null | undefined) {
    if (!pct) return 'text-secondary'
    if (pct > 90) return 'text-red'
    if (pct > 70) return 'text-yellow'
    return 'text-green'
  }

  function memColor(pct: number | null | undefined) {
    if (!pct) return 'text-secondary'
    if (pct > 90) return 'text-red'
    if (pct > 75) return 'text-yellow'
    return 'text-green'
  }

  function diskColor(pct: number | null | undefined) {
    if (pct == null) return 'text-secondary'
    if (pct > 90) return 'text-red'
    if (pct > 75) return 'text-yellow'
    return 'text-green'
  }

  function isAgentUpToDate(version: string) {
    return version && latestAgentVersion.value && version === latestAgentVersion.value
  }

  async function fetchProxmoxSummary() {
    try {
      const res = await apiClient.getProxmoxSummary()
      dashboardStore.setProxmoxSummary(res.data)
    } catch {
      // non-critique
    }
  }

  onMounted(() => {
    loading.value = true
    fetchSummary()
    fetchProxmoxSummary()
    apiClient
      .getSettings()
      .then((r) => {
        latestAgentVersion.value = r.data?.settings?.latestAgentVersion || ''
      })
      .catch(() => {})
    apiClient
      .getAptCVESummary()
      .then((r) => {
        cveSummary.value = r.data
      })
      .catch(() => {})
  })

  return {
    hosts,
    aptPending,
    versionComparisons,
    proxmoxSummary,
    hasProxmox,
    outdatedDockerImages,
    latestAgentVersion,
    cveSummary,
    proxmoxNodes,
    proxmoxLinks,
    hostMetrics,
    aptPendingHosts,
    diskUsage,
    loading,
    searchQuery,
    statusFilter,
    sortKey,
    sortDir,
    selectedHostIds,
    aptLoading,
    showDockerVersions,
    summaryHours,
    summaryChartData,
    summaryLoading,
    chartSource,
    chartSources,
    selectedCount,
    canRunApt,
    wsStatus,
    wsError,
    retryCount,
    reconnect,
    effectiveMetrics,
    filteredHosts,
    sortedHosts,
    summaryChartOptions,
    fetchSummary,
    changeSummaryRange,
    selectAllFiltered,
    clearSelection,
    sendBulkApt,
    formatUptime,
    cpuColor,
    memColor,
    diskColor,
    isAgentUpToDate,
  }
}

import { computed, onMounted, ref, Ref, ComputedRef } from 'vue'
import { useRoute } from 'vue-router'
import api from '../api'
import { useConfirmDialog } from './useConfirmDialog'

interface GitWebhook {
  id: string
  name: string
  enabled: boolean
  secret?: string
  last_execution?: any
  [key: string]: any
}

interface ReleaseTracker {
  id: string
  name: string
  enabled: boolean
  provider: string
  repo_owner: string
  repo_name: string
  last_release_tag?: string
  last_execution?: any
  [key: string]: any
}

interface Host {
  id: string
  [key: string]: any
}

interface RecentExecution {
  triggered_at: string
  sourceId: string
  sourceName: string
  [key: string]: any
}

interface UseGitWebhooksPageApi {
  activeTab: Ref<string>
  hosts: Ref<Host[]>
  error: Ref<string>
  saving: Ref<boolean>
  modalError: Ref<string>
  webhooks: Ref<GitWebhook[]>
  loadingWebhooks: Ref<boolean>
  showWebhookModal: Ref<boolean>
  editingWebhook: Ref<GitWebhook | null>
  newWebhookSecret: Ref<string>
  newWebhookId: Ref<string>
  trackers: Ref<ReleaseTracker[]>
  loadingTrackers: Ref<boolean>
  showTrackerModal: Ref<boolean>
  editingTracker: Ref<ReleaseTracker | null>
  prefillDockerImage: Ref<string>
  prefillDockerTag: Ref<string>
  recentWebhookExecutions: ComputedRef<RecentExecution[]>
  recentTrackerExecutions: ComputedRef<RecentExecution[]>
  openCreateWebhook: () => void
  openEditWebhook: (webhook: GitWebhook) => void
  closeWebhookModal: () => void
  saveWebhook: (payload: any) => Promise<void>
  toggleWebhook: (webhook: GitWebhook) => Promise<void>
  confirmDeleteWebhook: (webhook: GitWebhook) => Promise<void>
  closeSecretModal: () => void
  openCreateTracker: () => void
  openEditTracker: (tracker: ReleaseTracker) => void
  closeTrackerModal: () => void
  saveTracker: (payload: any) => Promise<void>
  toggleTracker: (tracker: ReleaseTracker) => Promise<void>
  checkNow: (tracker: ReleaseTracker) => Promise<void>
  confirmDeleteTracker: (tracker: ReleaseTracker) => Promise<void>
  repoURL: (tracker: ReleaseTracker) => string
  providerBadge: (provider: string) => string
  execStatusBadge: (status: string) => string
  formatRelative: (dateStr: string) => string
}

export function useGitWebhooksPage(): UseGitWebhooksPageApi {
  const dialog = useConfirmDialog()
  const route = useRoute()

  const activeTab: Ref<string> = ref('webhooks')
  const hosts: Ref<Host[]> = ref([])
  const error: Ref<string> = ref('')
  const saving: Ref<boolean> = ref(false)
  const modalError: Ref<string> = ref('')
  const webhooks: Ref<GitWebhook[]> = ref([])
  const loadingWebhooks: Ref<boolean> = ref(false)
  const showWebhookModal: Ref<boolean> = ref(false)
  const editingWebhook: Ref<GitWebhook | null> = ref(null)
  const newWebhookSecret: Ref<string> = ref('')
  const newWebhookId: Ref<string> = ref('')
  const trackers: Ref<ReleaseTracker[]> = ref([])
  const loadingTrackers: Ref<boolean> = ref(false)
  const showTrackerModal: Ref<boolean> = ref(false)
  const editingTracker: Ref<ReleaseTracker | null> = ref(null)

  const prefillDockerImage: Ref<string> = ref('')
  const prefillDockerTag: Ref<string> = ref('')

  const recentWebhookExecutions: ComputedRef<RecentExecution[]> = computed(() =>
    webhooks.value
      .filter((webhook) => webhook.last_execution)
      .map((webhook) => ({
        ...webhook.last_execution,
        sourceId: webhook.id,
        sourceName: webhook.name,
        repo_name: webhook.last_execution.repo_name || webhook.repo_filter || webhook.name,
        branch: webhook.last_execution.branch || webhook.branch_filter || '',
      }))
      .sort((left, right) => new Date(right.triggered_at).getTime() - new Date(left.triggered_at).getTime())
  )

  const recentTrackerExecutions: ComputedRef<RecentExecution[]> = computed(() =>
    trackers.value
      .filter((tracker) => tracker.last_execution)
      .map((tracker) => ({
        ...tracker.last_execution,
        sourceId: tracker.id,
        tag_name: tracker.last_execution.tag_name || tracker.last_release_tag,
        release_name: tracker.last_execution.release_name || tracker.name,
      }))
      .sort((left, right) => new Date(right.triggered_at).getTime() - new Date(left.triggered_at).getTime())
  )

  onMounted(async () => {
    if (route.query.tab === 'trackers') {
      activeTab.value = 'trackers'
    }
    if (route.query.docker_image) {
      prefillDockerImage.value = String(route.query.docker_image)
      prefillDockerTag.value = String(route.query.docker_tag || 'latest')
      activeTab.value = 'trackers'
      await Promise.all([loadWebhooks(), loadTrackers(), loadHosts()])
      openCreateTracker()
      return
    }
    await Promise.all([loadWebhooks(), loadTrackers(), loadHosts()])
  })

  async function loadWebhooks(): Promise<void> {
    loadingWebhooks.value = true
    try {
      error.value = ''
      const response = await api.getGitWebhooks()
      webhooks.value = response.data.webhooks || []
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur lors du chargement des webhooks'
    } finally {
      loadingWebhooks.value = false
    }
  }

  async function loadTrackers(): Promise<void> {
    loadingTrackers.value = true
    try {
      error.value = ''
      const response = await api.getReleaseTrackers()
      trackers.value = response.data.trackers || []
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur lors du chargement des trackers'
    } finally {
      loadingTrackers.value = false
    }
  }

  async function loadHosts(): Promise<void> {
    try {
      const response = await api.getHosts()
      hosts.value = response.data || []
    } catch {
      hosts.value = []
    }
  }

  function openCreateWebhook(): void {
    editingWebhook.value = null
    modalError.value = ''
    showWebhookModal.value = true
  }

  function openEditWebhook(webhook: GitWebhook): void {
    editingWebhook.value = webhook
    modalError.value = ''
    showWebhookModal.value = true
  }

  function closeWebhookModal(): void {
    showWebhookModal.value = false
    editingWebhook.value = null
    modalError.value = ''
  }

  async function saveWebhook(payload: any): Promise<void> {
    saving.value = true
    modalError.value = ''
    try {
      if (editingWebhook.value) {
        await api.updateGitWebhook(editingWebhook.value.id, payload)
      } else {
        const response: any = await api.createGitWebhook(payload)
        const created = response.data.webhook
        if (created?.secret) {
          newWebhookId.value = created.id
          newWebhookSecret.value = created.secret
        }
      }
      closeWebhookModal()
      await loadWebhooks()
    } catch (err: any) {
      modalError.value = err.response?.data?.error || 'Erreur'
    } finally {
      saving.value = false
    }
  }

  async function toggleWebhook(webhook: GitWebhook): Promise<void> {
    try {
      await api.updateGitWebhook(webhook.id, { ...webhook, enabled: !webhook.enabled })
      await loadWebhooks()
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur'
    }
  }

  async function confirmDeleteWebhook(webhook: GitWebhook): Promise<void> {
    const ok = await dialog.confirm({
      title: `Supprimer le webhook "${webhook.name}" ?`,
      message: 'Toutes les executions associees seront egalement supprimees.',
      variant: 'danger',
    })
    if (!ok) return
    try {
      await api.deleteGitWebhook(webhook.id)
      await loadWebhooks()
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur lors de la suppression'
    }
  }

  function closeSecretModal(): void {
    newWebhookSecret.value = ''
    newWebhookId.value = ''
  }

  function openCreateTracker(): void {
    editingTracker.value = null
    modalError.value = ''
    showTrackerModal.value = true
  }

  function openEditTracker(tracker: ReleaseTracker): void {
    prefillDockerImage.value = ''
    prefillDockerTag.value = ''
    editingTracker.value = tracker
    modalError.value = ''
    showTrackerModal.value = true
  }

  function closeTrackerModal(): void {
    showTrackerModal.value = false
    editingTracker.value = null
    modalError.value = ''
    prefillDockerImage.value = ''
    prefillDockerTag.value = ''
  }

  async function saveTracker(payload: any): Promise<void> {
    saving.value = true
    modalError.value = ''
    try {
      if (editingTracker.value) {
        await api.updateReleaseTracker(editingTracker.value.id, payload)
      } else {
        await api.createReleaseTracker(payload)
      }
      closeTrackerModal()
      await loadTrackers()
    } catch (err: any) {
      modalError.value = err.response?.data?.error || 'Erreur'
    } finally {
      saving.value = false
    }
  }

  async function toggleTracker(tracker: ReleaseTracker): Promise<void> {
    try {
      await api.updateReleaseTracker(tracker.id, { ...tracker, enabled: !tracker.enabled })
      await loadTrackers()
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur'
    }
  }

  async function checkNow(tracker: ReleaseTracker): Promise<void> {
    try {
      await api.checkReleaseTrackerNow(tracker.id)
      setTimeout(() => loadTrackers(), 2000)
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur'
    }
  }

  async function confirmDeleteTracker(tracker: ReleaseTracker): Promise<void> {
    const ok = await dialog.confirm({
      title: `Supprimer le tracker "${tracker.name}" ?`,
      message: 'Toutes les executions associees seront egalement supprimees.',
      variant: 'danger',
    })
    if (!ok) return
    try {
      await api.deleteReleaseTracker(tracker.id)
      await loadTrackers()
    } catch (err: any) {
      error.value = err.response?.data?.error || 'Erreur lors de la suppression'
    }
  }

  function repoURL(tracker: ReleaseTracker): string {
    switch (tracker.provider) {
      case 'gitlab':
        return `https://gitlab.com/${tracker.repo_owner}/${tracker.repo_name}`
      case 'gitea':
        return `https://codeberg.org/${tracker.repo_owner}/${tracker.repo_name}`
      default:
        return `https://github.com/${tracker.repo_owner}/${tracker.repo_name}`
    }
  }

  function providerBadge(provider: string): string {
    const map: Record<string, string> = {
      github: 'bg-blue-lt text-blue',
      gitlab: 'bg-orange-lt text-orange',
      gitea: 'bg-teal-lt text-teal',
      forgejo: 'bg-purple-lt text-purple',
      custom: 'bg-secondary-lt text-secondary',
    }
    return map[provider] || 'bg-secondary-lt text-secondary'
  }

  function execStatusBadge(status: string): string {
    const map: Record<string, string> = {
      pending: 'bg-yellow-lt text-yellow',
      running: 'bg-blue-lt text-blue',
      completed: 'bg-success-lt text-success',
      failed: 'bg-danger-lt text-danger',
      skipped: 'bg-secondary-lt text-secondary',
    }
    return map[status] || 'bg-secondary-lt text-secondary'
  }

  function formatRelative(dateStr: string): string {
    if (!dateStr) return '-'
    return new Date(dateStr).toLocaleString('fr-FR')
  }

  return {
    activeTab,
    hosts,
    error,
    saving,
    modalError,
    webhooks,
    loadingWebhooks,
    showWebhookModal,
    editingWebhook,
    newWebhookSecret,
    newWebhookId,
    trackers,
    loadingTrackers,
    showTrackerModal,
    editingTracker,
    prefillDockerImage,
    prefillDockerTag,
    recentWebhookExecutions,
    recentTrackerExecutions,
    openCreateWebhook,
    openEditWebhook,
    closeWebhookModal,
    saveWebhook,
    toggleWebhook,
    confirmDeleteWebhook,
    closeSecretModal,
    openCreateTracker,
    openEditTracker,
    closeTrackerModal,
    saveTracker,
    toggleTracker,
    checkNow,
    confirmDeleteTracker,
    repoURL,
    providerBadge,
    execStatusBadge,
    formatRelative,
  }
}

import { ref, Ref } from 'vue'

type CommandStatus = 'pending' | 'running' | 'completed' | 'failed' | 'success' | 'error'

interface NormalizedHostCommand {
  id: string | number
  host_name?: string
  module?: string
  action?: string
  target?: string
  prefix: string
  command: string
  status: CommandStatus | string
  output: string
}

interface RawCommand {
  [key: string]: any
}

interface UseHostCommandConsoleApi {
  liveCommand: Ref<NormalizedHostCommand | null>
  showConsole: Ref<boolean>
  openCommand: (command: RawCommand | null | undefined) => void
  closeConsole: () => void
  updateCommand: (command: NormalizedHostCommand | null) => void
  normalizeCommand: (command: RawCommand | null | undefined) => NormalizedHostCommand | null
}

export function useHostCommandConsole(): UseHostCommandConsoleApi {
  const liveCommand: Ref<NormalizedHostCommand | null> = ref(null)
  const showConsole: Ref<boolean> = ref(false)

  /**
   * Normalizes multiple command payload shapes into a single console-friendly shape.
   */
  function normalizeCommand(command: RawCommand | null | undefined): NormalizedHostCommand | null {
    if (!command) return null

    const host_name = command.host_name || ''

    if (command.commandId) {
      return {
        id: command.commandId,
        host_name,
        module: command.module || 'custom',
        action: command.action || command.command || '',
        target: command.target || '',
        prefix: command.prefix || '',
        command: command.command || '',
        status: command.status || 'running',
        output: command.output || '',
      }
    }

    if (command.command && Object.prototype.hasOwnProperty.call(command, 'prefix')) {
      return {
        id: command.id,
        host_name,
        module: command.module || 'custom',
        action: command.action || command.command || '',
        target: command.target || '',
        prefix: command.prefix || '',
        command: command.command || '',
        status: command.status || 'pending',
        output: command.output || '',
      }
    }

    let displayCommand: string
    let prefix = ''
    const module = command.module || 'apt'
    if (module === 'apt') {
      prefix = 'apt '
      displayCommand = command.action || command.command
    } else if (module === 'journal') {
      displayCommand = `journalctl -u ${command.target || command.container_name}`
    } else {
      displayCommand = `${command.action || ''} ${command.target || command.container_name || ''}`.trim()
    }

    return {
      id: command.id,
      host_name,
      module,
      action: command.action || '',
      target: command.target || command.container_name || '',
      prefix,
      command: displayCommand,
      status: command.status || 'pending',
      output: command.output || '',
    }
  }

  function openCommand(command: RawCommand | null | undefined): void {
    liveCommand.value = normalizeCommand(command)
    showConsole.value = true
  }

  function closeConsole(): void {
    showConsole.value = false
    liveCommand.value = null
  }

  function updateCommand(command: NormalizedHostCommand | null): void {
    liveCommand.value = command
  }

  return {
    liveCommand,
    showConsole,
    openCommand,
    closeConsole,
    updateCommand,
    normalizeCommand,
  }
}

import { computed, nextTick, onMounted, ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import apiClient from '../api'
import { useHostCommandConsole } from './useHostCommandConsole'
import { useCommandStream } from './useCommandStream'
import { useConfirmDialog } from './useConfirmDialog'
import { useWebSocket } from './useWebSocket'
import { useAuthStore } from '../stores/auth'

type AnyRecord = Record<string, any>

export function useHostDetail() {
  const route = useRoute()
  const router = useRouter()
  const hostId = String(route.params.id)

  const auth = useAuthStore()
  const dialog = useConfirmDialog()
  const canRunApt = computed(() => auth.canManage)

  const activeTab = ref('metrics')
  const isEditing = ref(false)
  const tasksCount = ref(0)
  const aptCmdLoading = ref('')

  const host = ref<AnyRecord | null>(null)
  const metrics = ref<AnyRecord | null>(null)
  const containers = ref<AnyRecord[]>([])
  const versionComparisons = ref<AnyRecord[]>([])
  const aptStatus = ref<AnyRecord | null>(null)
  const cmdHistory = ref<AnyRecord[]>([])
  const diskMetrics = ref<AnyRecord | null>(null)
  const diskHealth = ref<AnyRecord | null>(null)
  const latestAgentVersion = ref('')

  const proxmoxLink = ref<AnyRecord | null>(null)
  const linkSaving = ref(false)

  const effectiveMetrics = computed(() => {
    const m = metrics.value
    const link = proxmoxLink.value
    if (!m || !link || link.status !== 'confirmed') return m

    const src = link.metrics_source ?? 'auto'
    const useProxmox = src === 'proxmox' || (src === 'auto' && (link.mem_alloc ?? 0) > 0)

    if (!useProxmox) return m

    const cpuPct = (link.cpu_usage ?? 0) * 100
    const memUsed = link.mem_usage ?? 0
    const memTotal = link.mem_alloc ?? 0
    return {
      ...m,
      cpu_usage_percent: cpuPct,
      memory_used: memUsed,
      memory_total: memTotal,
      memory_percent: memTotal > 0 ? (memUsed / memTotal) * 100 : 0,
    }
  })

  const effectiveMetricsSource = computed(() => {
    const link = proxmoxLink.value
    if (!link || link.status !== 'confirmed') return 'agent'
    const src = link.metrics_source ?? 'auto'
    if (src === 'proxmox') return 'proxmox'
    if (src === 'auto' && (link.mem_alloc ?? 0) > 0) return 'proxmox'
    return 'agent'
  })
  const showLinkForm = ref(false)
  const showLinkButton = ref(false)
  const linkCandidates = ref<AnyRecord[]>([])
  const linkCandidatesLoading = ref(false)
  const selectedCandidate = ref('')

  const { liveCommand, showConsole, openCommand: _openCommand, closeConsole, updateCommand } = useHostCommandConsole()
  const { openCommandStream, closeStream } = useCommandStream({ token: () => auth.token })

  function openCommand(rawCmd: AnyRecord) {
    _openCommand({ ...rawCmd, host_name: host.value?.hostname })
  }

  function connectStream(commandId: string) {
    openCommandStream(commandId, {
      onInit: (p: AnyRecord) => {
        const current = liveCommand.value
        if (!current) return
        updateCommand({ ...current, status: p.status, output: p.output || '' })
        nextTick(() => {})
      },
      onChunk: (p: AnyRecord) => {
        const current = liveCommand.value
        if (!current) return
        updateCommand({ ...current, output: (current.output || '') + (p.chunk || '') })
      },
      onStatus: (p: AnyRecord) => {
        const current = liveCommand.value
        if (!current) return
        updateCommand({ ...current, status: p.status })
        if (p.status === 'completed' || p.status === 'failed') {
          loadCmdHistoryRefresh()
        }
      },
    })
  }

  watch(
    () => liveCommand.value?.id,
    (id: string | number | undefined) => {
      if (!id || !showConsole.value) return
      connectStream(String(id))
    }
  )

  watch(showConsole, (show) => {
    if (!show) {
      closeStream()
    } else if (liveCommand.value?.id) {
      connectStream(String(liveCommand.value.id))
    }
  })

  function closeConsoleAndStream() {
    closeStream()
    closeConsole()
  }

  function clearConsoleOutput() {
    if (liveCommand.value) updateCommand({ ...liveCommand.value, output: '' })
  }

  const { wsStatus, wsError, retryCount, reconnect } = useWebSocket(
    `/api/v1/ws/hosts/${hostId}`,
    (payload: AnyRecord) => {
      if (payload.type !== 'host_detail') return
      host.value = payload.host
      metrics.value = payload.metrics
      containers.value = payload.containers || []
      versionComparisons.value = payload.version_comparisons || []
      aptStatus.value = payload.apt_status
      if ('proxmox_link' in payload) {
        proxmoxLink.value = payload.proxmox_link
      }
    },
    { debounceMs: 200 }
  )

  async function sendAptCmd(command: string) {
    const confirmed = await dialog.confirm({
      title: `apt ${command}`,
      message: `Exécuter sur : ${host.value?.hostname}`,
      variant: command === 'dist-upgrade' ? 'danger' : 'warning',
    })

    if (!confirmed) return

    aptCmdLoading.value = command
    try {
      const response = await apiClient.sendAptCommand([hostId], command)
      if (response.data?.commands?.length > 0) {
        const cmd = response.data.commands[0]
        if (cmd.command_id) {
          openCommand({ id: cmd.command_id, module: 'apt', action: command, status: 'pending', output: '' })
        }
      }
    } catch (e: any) {
      await dialog.confirm({
        title: 'Erreur',
        message: e.response?.data?.error || e.message,
        variant: 'danger',
      })
    } finally {
      aptCmdLoading.value = ''
    }
  }

  function isAgentUpToDate(version: string) {
    if (!version || !latestAgentVersion.value) return false
    return version === latestAgentVersion.value
  }

  async function loadComplete() {
    try {
      const res = await apiClient.getHostComplete(hostId)
      const d = res.data
      if (d.host) host.value = d.host
      if (d.metrics) metrics.value = d.metrics
      if (d.containers) containers.value = d.containers
      if (d.apt_status) aptStatus.value = d.apt_status
      if (d.disk_metrics) diskMetrics.value = d.disk_metrics
      if (d.disk_health) diskHealth.value = d.disk_health
      if (d.command_history) cmdHistory.value = d.command_history
      if (d.latest_agent_version) latestAgentVersion.value = d.latest_agent_version
    } catch {
      // Non-critical — WS will populate live data
    }
  }

  async function loadCmdHistoryRefresh() {
    try {
      const res = await apiClient.getHostCommandHistory(hostId)
      cmdHistory.value = res.data?.commands || []
    } catch {
      cmdHistory.value = []
    }
  }

  async function deleteHost() {
    const confirmed = await dialog.confirm({
      title: "Supprimer l'hôte",
      message: 'Cette action est irréversible. Toutes les données associées seront supprimées.',
      variant: 'danger',
      requiredText: host.value?.hostname || host.value?.name,
    })

    if (!confirmed) return

    try {
      await apiClient.deleteHost(hostId)
      router.push('/')
    } catch (e: any) {
      await dialog.confirm({
        title: 'Erreur',
        message: e.response?.data?.error || e.message,
        variant: 'danger',
      })
    }
  }

  async function loadProxmoxLink() {
    try {
      const res = await apiClient.getHostProxmoxLink(hostId)
      proxmoxLink.value = res.data
      if (!res.data) {
        const cands = await apiClient.getHostProxmoxCandidates(hostId).catch(() => ({ data: [] }))
        showLinkButton.value = (cands.data?.length ?? 0) > 0
      }
    } catch {
      proxmoxLink.value = null
      showLinkButton.value = false
    }
  }

  async function confirmLink() {
    if (!proxmoxLink.value) return
    linkSaving.value = true
    try {
      const res = await apiClient.updateProxmoxLink(proxmoxLink.value.id, { status: 'confirmed' })
      proxmoxLink.value = res.data
    } finally {
      linkSaving.value = false
    }
  }

  async function ignoreLink() {
    if (!proxmoxLink.value) return
    linkSaving.value = true
    try {
      await apiClient.updateProxmoxLink(proxmoxLink.value.id, { status: 'ignored' })
      proxmoxLink.value = null
      showLinkButton.value = true
    } finally {
      linkSaving.value = false
    }
  }

  async function changeMetricsSource(source: 'agent' | 'proxmox' | 'auto') {
    if (!proxmoxLink.value) return
    linkSaving.value = true
    try {
      const res = await apiClient.updateProxmoxLink(proxmoxLink.value.id, { metrics_source: source })
      proxmoxLink.value = res.data
    } finally {
      linkSaving.value = false
    }
  }

  async function deleteLink() {
    if (!proxmoxLink.value) return
    linkSaving.value = true
    try {
      await apiClient.deleteProxmoxLink(proxmoxLink.value.id)
      proxmoxLink.value = null
      showLinkButton.value = true
    } finally {
      linkSaving.value = false
    }
  }

  async function openLinkForm() {
    showLinkForm.value = true
    if (linkCandidates.value.length > 0) return
    linkCandidatesLoading.value = true
    try {
      const res = await apiClient.getHostProxmoxCandidates(hostId)
      linkCandidates.value = res.data || []
    } finally {
      linkCandidatesLoading.value = false
    }
  }

  async function createManualLink() {
    if (!selectedCandidate.value) return
    linkSaving.value = true
    try {
      const res = await apiClient.createProxmoxLink({
        guest_id: selectedCandidate.value,
        host_id: hostId,
        status: 'confirmed',
        metrics_source: 'auto',
      })
      proxmoxLink.value = res.data
      showLinkForm.value = false
      showLinkButton.value = false
      selectedCandidate.value = ''
    } finally {
      linkSaving.value = false
    }
  }

  function formatBytesLink(bytes: number) {
    if (!bytes) return '0 B'
    const units = ['B', 'Ko', 'Mo', 'Go', 'To']
    let i = 0
    let v = bytes
    while (v >= 1024 && i < units.length - 1) {
      v /= 1024
      i++
    }
    return `${v.toFixed(i === 0 ? 0 : 1)} ${units[i]}`
  }

  const hostPerms = ref<AnyRecord[]>([])
  const permLoading = ref(false)
  const addPermModal = ref(false)
  const newPermUsername = ref('')
  const newPermLevel = ref('viewer')
  const permSaving = ref(false)
  const permError = ref('')
  const allUsers = ref<AnyRecord[]>([])

  const availableUsers = computed(() =>
    allUsers.value.filter((u: AnyRecord) => u.role !== 'admin' && !hostPerms.value.some((p: AnyRecord) => p.username === u.username))
  )

  async function loadHostPerms() {
    if (!auth.isAdmin) return
    permLoading.value = true
    try {
      const [permsRes, usersRes] = await Promise.all([apiClient.getHostPermissions(hostId), apiClient.getUsers()])
      hostPerms.value = permsRes.data || []
      allUsers.value = usersRes.data || []
    } finally {
      permLoading.value = false
    }
  }

  function openAddPermission() {
    newPermUsername.value = ''
    newPermLevel.value = 'viewer'
    permError.value = ''
    addPermModal.value = true
  }

  async function savePermission() {
    permSaving.value = true
    permError.value = ''
    try {
      await apiClient.setHostPermission(hostId, newPermUsername.value, newPermLevel.value)
      addPermModal.value = false
      await loadHostPerms()
    } catch (e: any) {
      permError.value = e?.response?.data?.error || "Erreur lors de l'enregistrement"
    } finally {
      permSaving.value = false
    }
  }

  async function revokePermission(username: string) {
    try {
      await apiClient.deleteHostPermission(hostId, username)
      await loadHostPerms()
    } catch {
      // ignore
    }
  }

  onMounted(() => {
    loadComplete()
    loadProxmoxLink()
    loadHostPerms()
  })

  return {
    auth,
    hostId,
    canRunApt,
    activeTab,
    isEditing,
    tasksCount,
    aptCmdLoading,
    host,
    containers,
    versionComparisons,
    aptStatus,
    cmdHistory,
    diskMetrics,
    diskHealth,
    proxmoxLink,
    linkSaving,
    effectiveMetrics,
    effectiveMetricsSource,
    showLinkForm,
    showLinkButton,
    linkCandidates,
    linkCandidatesLoading,
    selectedCandidate,
    liveCommand,
    showConsole,
    wsStatus,
    wsError,
    retryCount,
    reconnect,
    openCommand,
    sendAptCmd,
    isAgentUpToDate,
    deleteHost,
    loadCmdHistoryRefresh,
    confirmLink,
    ignoreLink,
    changeMetricsSource,
    deleteLink,
    openLinkForm,
    createManualLink,
    closeConsoleAndStream,
    clearConsoleOutput,
    formatBytesLink,
    hostPerms,
    permLoading,
    addPermModal,
    newPermUsername,
    newPermLevel,
    permSaving,
    permError,
    availableUsers,
    openAddPermission,
    savePermission,
    revokePermission,
  }
}

import { ref, watch, Ref } from 'vue'

/**
 * A reactive ref that is persisted to localStorage.
 * @param key - localStorage key
 * @param defaultValue - value to use if the key does not exist
 * @returns A reactive ref bound to localStorage
 */
export function useLocalStorage<T = any>(key: string, defaultValue: T): Ref<T> {
  const stored = localStorage.getItem(key)
  let initial: any = defaultValue
  if (stored !== null) {
    try {
      initial = JSON.parse(stored)
    } catch {
      // Legacy value stored without JSON.stringify — use as-is and re-persist in correct format
      initial = stored
    }
  }

  const value: Ref<T> = ref(initial)

  watch(value, (newVal: T) => {
    if (newVal === null || newVal === undefined) {
      localStorage.removeItem(key)
    } else {
      localStorage.setItem(key, JSON.stringify(newVal))
    }
  })

  return value
}

import { computed, isRef, ref, watch, Ref, ComputedRef } from 'vue'

type RefLike<T> = { value: T } | Ref<T>

interface PaginationOptions<T> {
  items?: T[] | RefLike<T[]>
  pageSize?: number
  initialPage?: number
}

interface PaginationApi<T> {
  currentPage: Ref<number>
  totalItems: ComputedRef<number>
  totalPages: ComputedRef<number>
  pagedItems: ComputedRef<T[]>
  nextPage: () => void
  prevPage: () => void
  resetPage: () => void
  setPage: (page: number) => void
}

interface RemotePaginationApi {
  nextPage: () => void
  prevPage: () => void
}

export function usePagination<T>({ items, pageSize = 10, initialPage = 1 }: PaginationOptions<T> = {}): PaginationApi<T> {
  const currentPage: Ref<number> = ref(initialPage)
  const safePageSize = Math.max(1, pageSize)

  const sourceItems: ComputedRef<T[]> = computed(() => {
    if (!items) return []
    return isRef(items) ? (items as any).value : items
  })

  const totalItems: ComputedRef<number> = computed(() => sourceItems.value.length)
  const totalPages: ComputedRef<number> = computed(() => Math.max(1, Math.ceil(totalItems.value / safePageSize)))

  watch(totalPages, (maxPage) => {
    if (currentPage.value > maxPage) currentPage.value = maxPage
  })

  const pagedItems: ComputedRef<T[]> = computed(() => {
    const start = (currentPage.value - 1) * safePageSize
    return sourceItems.value.slice(start, start + safePageSize)
  })

  function nextPage(): void {
    if (currentPage.value < totalPages.value) currentPage.value += 1
  }

  function prevPage(): void {
    if (currentPage.value > 1) currentPage.value -= 1
  }

  function resetPage(): void {
    currentPage.value = 1
  }

  function setPage(page: number): void {
    currentPage.value = Math.min(Math.max(1, page), totalPages.value)
  }

  return {
    currentPage,
    totalItems,
    totalPages,
    pagedItems,
    nextPage,
    prevPage,
    resetPage,
    setPage,
  }
}

interface RemotePaginationOptions {
  currentPage: RefLike<number>
  totalPages: RefLike<number>
}

export function useRemotePagination({ currentPage, totalPages }: RemotePaginationOptions): RemotePaginationApi {
  const safeCurrentPage = isRef(currentPage) ? currentPage : (currentPage as { value: number })
  const safeTotalPages = isRef(totalPages) ? totalPages : (totalPages as { value: number })

  function nextPage(): void {
    if (safeCurrentPage.value < safeTotalPages.value) safeCurrentPage.value += 1
  }

  function prevPage(): void {
    if (safeCurrentPage.value > 1) safeCurrentPage.value -= 1
  }

  return { nextPage, prevPage }
}

import { ref, onMounted, onUnmounted, Ref } from 'vue'
import { formatRelativeTime } from './useDateFormatter'

type RelativeDateInput =
  | string
  | Date
  | null
  | undefined
  | { value: string | Date | null | undefined }
  | (() => string | Date | null | undefined)

/**
 * Composable to display a timestamp in relative time with automatic updates.
 */
export function useRelativeTime(dateInput: RelativeDateInput, updateInterval: number = 1000): Ref<string> {
  const relativeText: Ref<string> = ref('')
  let intervalId: ReturnType<typeof setInterval> | null = null

  const resolveDate = (): string | Date | null | undefined => {
    if (typeof dateInput === 'function') return dateInput()
    return dateInput && typeof dateInput === 'object' && 'value' in dateInput
      ? (dateInput as any).value
      : dateInput
  }

  function updateRelativeTime(): void {
    relativeText.value = formatRelativeTime(resolveDate(), 'Jamais', true)
  }

  onMounted(() => {
    updateRelativeTime()
    intervalId = setInterval(updateRelativeTime, updateInterval)
  })

  onUnmounted(() => {
    if (intervalId) clearInterval(intervalId)
  })

  return relativeText
}

/**
 * Utility function to format a date without reactivity.
 */
export function formatRelativeTimeStatic(date: string | Date | null | undefined): string {
  return formatRelativeTime(date, 'Jamais', true)
}

import { onUnmounted, ref, Ref } from 'vue'

interface UseToastApi<T = any> {
  value: Ref<T | null>
  showToast: (nextValue: T, durationMs?: number) => void
  clearToast: () => void
}

export function useToast<T = any>(initialValue: T | null = null): UseToastApi<T> {
  const value: Ref<T | null> = ref(initialValue) as Ref<T | null>
  let timeoutId: ReturnType<typeof setTimeout> | null = null

  function clearToast(): void {
    if (timeoutId) {
      clearTimeout(timeoutId)
      timeoutId = null
    }
    value.value = initialValue
  }

  function showToast(nextValue: T, durationMs: number = 5000): void {
    if (timeoutId) clearTimeout(timeoutId)
    value.value = nextValue
    if (durationMs > 0) {
      timeoutId = setTimeout(() => {
        value.value = initialValue
        timeoutId = null
      }, durationMs)
    }
  }

  onUnmounted(() => {
    if (timeoutId) clearTimeout(timeoutId)
  })

  return {
    value,
    showToast,
    clearToast,
  }
}

import { ref, onMounted, onUnmounted, Ref } from 'vue'
import { useAuthStore } from '../stores/auth'

type WebSocketStatus = 'connecting' | 'connected' | 'reconnecting' | 'error' | 'disconnected'

interface UseWebSocketOptions {
  debounceMs?: number
}

interface SendOptions {
  stringify?: boolean
}

interface UseWebSocketApi {
  wsStatus: Ref<WebSocketStatus>
  wsError: Ref<string>
  retryCount: Ref<number>
  reconnect: () => void
  disconnect: () => void
  send: (message: unknown, options?: SendOptions) => boolean
}

/**
 * WebSocket status values:
 *   'connecting'   — initial connection attempt
 *   'connected'    — open and authenticated
 *   'reconnecting' — lost connection, retrying
 *   'error'        — blocked (403 origin, 401 auth) — no auto-retry
 *   'disconnected' — manually closed
 */
export function useWebSocket<TPayload = any>(
  path: string,
  onMessage: (payload: TPayload) => void,
  options: UseWebSocketOptions = {}
): UseWebSocketApi {
  const { debounceMs = 0 } = options
  const auth = useAuthStore()

  const wsStatus: Ref<WebSocketStatus> = ref('connecting')
  const wsError: Ref<string> = ref('')
  const retryCount: Ref<number> = ref(0)

  let ws: WebSocket | null = null
  let retryTimer: ReturnType<typeof setTimeout> | null = null
  let debounceTimer: ReturnType<typeof setTimeout> | null = null
  let manualClose = false

  // Exponential backoff: 2s, 4s, 8s, capped at 30s
  function retryDelay(): number {
    return Math.min(2000 * Math.pow(2, retryCount.value), 30000)
  }

  function connect(): void {
    if (!auth.token) return
    manualClose = false

    // Close any existing socket before opening a new one (prevents double-instance on reconnect)
    if (ws && ws.readyState !== WebSocket.CLOSED) {
      ws.onclose = null
      ws.close()
      ws = null
    }

    const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws'
    const url = `${protocol}://${window.location.host}${path}`
    ws = new WebSocket(url)

    ws.onopen = () => {
      ws!.send(JSON.stringify({ type: 'auth', token: auth.token }))
      // Status moves to 'connected' only after the first valid message
    }

    ws.onmessage = (event: MessageEvent) => {
      try {
        const payload = JSON.parse(event.data)

        // Auth error from server (invalid/expired token)
        if (payload.type === 'auth_error') {
          wsStatus.value = 'error'
          wsError.value = 'Authentification refusée — reconnectez-vous'
          ws!.close()
          return
        }

        // First valid message = truly connected
        if (wsStatus.value !== 'connected') {
          wsStatus.value = 'connected'
          wsError.value = ''
          retryCount.value = 0
        }

        if (debounceMs > 0) {
          clearTimeout(debounceTimer!)
          debounceTimer = setTimeout(() => onMessage(payload), debounceMs)
        } else {
          onMessage(payload)
        }
      } catch {
        // Ignore malformed payloads
      }
    }

    ws.onerror = () => {
      // onerror always fires just before onclose — let onclose handle retry logic
    }

    ws.onclose = (event: CloseEvent) => {
      if (manualClose) {
        wsStatus.value = 'disconnected'
        return
      }

      // 403 = origin rejected by CheckOrigin (misconfigured BASE_URL)
      // 1008 = policy violation
      if (event.code === 1002 || event.code === 1008) {
        wsStatus.value = 'error'
        wsError.value = 'Connexion refusée par le serveur — vérifiez la configuration BASE_URL'
        return // No retry — it will keep failing
      }

      // 4001 = custom auth error code we could use in future
      if (event.code === 4001) {
        wsStatus.value = 'error'
        wsError.value = 'Session expirée — rechargez la page'
        return
      }

      // For 403 (gorilla sends this as HTTP before upgrade), code will be 1006 (abnormal closure)
      // We detect it via the fact that we never reached 'connected'
      wsStatus.value = 'reconnecting'
      if (retryCount.value === 0) {
        wsError.value = 'Impossible de se connecter — vérifiez que le serveur est accessible et que BASE_URL est correctement configuré'
      } else {
        wsError.value = ''
      }

      retryCount.value++
      const delay = retryDelay()
      retryTimer = setTimeout(connect, delay)
    }
  }

  function disconnect(): void {
    manualClose = true
    if (retryTimer) clearTimeout(retryTimer)
    if (debounceTimer) clearTimeout(debounceTimer)
    if (ws) {
      ws.close()
      ws = null
    }
    wsStatus.value = 'disconnected'
  }

  function send(message: unknown, { stringify = true }: SendOptions = {}): boolean {
    if (!ws || ws.readyState !== WebSocket.OPEN) return false
    try {
      ws.send(stringify ? JSON.stringify(message) : (message as string))
      return true
    } catch {
      return false
    }
  }

  onMounted(connect)
  onUnmounted(disconnect)

  return { wsStatus, wsError, retryCount, reconnect: connect, disconnect, send }
}

