const router = createRouter({
  history: createWebHistory(),
  routes,
})

router.beforeEach(
  (to: RouteLocationNormalized, _from: RouteLocationNormalized, next: NavigationGuardNext) => {
    const auth = useAuthStore()
    const meta = to.meta as RouteMeta

    if (meta.requiresAuth && !auth.isAuthenticated) {
      next('/login')
    } else if (auth.isAuthenticated && auth.mustChangePassword && to.path !== '/account') {
      // Force password change before accessing any other page
      next('/account')
    } else if (meta.requiresAdmin && !auth.hasPermission('*')) {
      next('/')
    } else if (to.path === '/login' && auth.isAuthenticated) {
      next('/')
    } else {
      next()
    }
  }
)

// Recover from chunk load failures (network hiccup during lazy route import).
// The browser caches the old chunk references after a deployment; a hard
// reload fetches the new manifest and resolves the mismatch.
router.onError((error: any) => {
  const isChunkError =
    error?.name === 'ChunkLoadError' ||
    /loading chunk/i.test(error?.message || '') ||
    /failed to fetch dynamically imported module/i.test(error?.message || '')
  if (isChunkError) {
    window.location.reload()
  }
})

export default router

import { ref, Ref } from 'vue'
import { defineStore } from 'pinia'
import apiClient from '../api'

const TTL_MS = 30_000 // 30 seconds

interface AlertRule {
  id?: number
  [key: string]: any
}

export const useAlertRulesStore = defineStore('alertRules', () => {
  const rules: Ref<AlertRule[]> = ref([])
  const loading: Ref<boolean> = ref(false)
  const error: Ref<string> = ref('')
  const fetched: Ref<boolean> = ref(false)
  const fetchedAt: Ref<number | null> = ref(null)

  async function fetchRules(force: boolean = false): Promise<void> {
    if (!force && fetchedAt.value && Date.now() - fetchedAt.value < TTL_MS) {
      fetched.value = true
      return
    }
    loading.value = true
    error.value = ''
    try {
      const res = await apiClient.getAlertRules()
      rules.value = res.data || []
      fetchedAt.value = Date.now()
    } catch (e: any) {
      // Keep stale data on error
      error.value = e?.response?.data?.error || e?.message || 'Erreur de chargement'
    } finally {
      loading.value = false
      fetched.value = true
    }
  }

  function invalidate(): void {
    fetchedAt.value = null
    fetched.value = false
  }

  return { rules, loading, error, fetched, fetchRules, invalidate }
})

import { ref, Ref } from 'vue'
import { defineStore } from 'pinia'
import apiClient from '../api'

const TTL_MS = 60_000 // 1 minute

interface Host {
  id: string
  [key: string]: any
}

export const useHostsStore = defineStore('hosts', () => {
  const hosts: Ref<Host[]> = ref([])
  const loading: Ref<boolean> = ref(false)
  const fetchedAt: Ref<number | null> = ref(null)

  async function fetchHosts(force: boolean = false): Promise<void> {
    if (!force && fetchedAt.value && Date.now() - fetchedAt.value < TTL_MS) return
    loading.value = true
    try {
      const res = await apiClient.getHosts()
      hosts.value = res.data || []
      fetchedAt.value = Date.now()
    } catch {
      // Keep stale data on error
    } finally {
      loading.value = false
    }
  }

  function invalidate(): void {
    fetchedAt.value = null
  }

  function upsert(host: Host): void {
    const idx = hosts.value.findIndex((h) => h.id === host.id)
    if (idx >= 0) {
      hosts.value = [...hosts.value.slice(0, idx), host, ...hosts.value.slice(idx + 1)]
    } else {
      hosts.value = [...hosts.value, host]
    }
  }

  function remove(hostId: string): void {
    hosts.value = hosts.value.filter((h) => h.id !== hostId)
  }

  return { hosts, loading, fetchHosts, invalidate, upsert, remove }
})
